    "html": "<div class=\"d-backlog-065\" role=\"group\" aria-label=\"Scroll Clip Morph interactive demonstration\" tabindex=\"0\"><canvas class=\"d-backlog-065-canvas\" aria-hidden=\"true\"></canvas><div class=\"d-backlog-065-scroller\" tabindex=\"0\"><div class=\"d-backlog-065-spacer\"><strong>01</strong><strong>02</strong><strong>03</strong><strong>04</strong></div></div><div class=\"d-backlog-065-hud\"><span>SCROLL</span><b>Scroll Clip Morph</b><em>00</em></div><div class=\"d-backlog-065-objects\" aria-hidden=\"true\"><i style=\"--i:0\"></i><i style=\"--i:1\"></i><i style=\"--i:2\"></i><i style=\"--i:3\"></i><i style=\"--i:4\"></i><i style=\"--i:5\"></i><i style=\"--i:6\"></i><i style=\"--i:7\"></i><i style=\"--i:8\"></i></div><button class=\"d-backlog-065-action\" type=\"button\">Activate</button></div>",
    "css": ".d-backlog-065{position:relative;width:100%;height:320px;overflow:hidden;isolation:isolate;background:#0a0a0b;color:#ececef;touch-action:none;font-family:\"JetBrains Mono\",monospace}.d-backlog-065-canvas{position:absolute;inset:0;width:100%;height:100%}.d-backlog-065-hud{position:absolute;z-index:4;inset:18px 20px auto;display:grid;grid-template-columns:1fr auto;gap:5px;pointer-events:none}.d-backlog-065-hud span{color:#5c5c66;font-size:9px;letter-spacing:.14em}.d-backlog-065-hud b{grid-column:1;color:#ececef;font-size:13px;font-weight:500}.d-backlog-065-hud em{grid-row:1/3;grid-column:2;color:#c8ff2e;font-size:22px;font-style:normal}.d-backlog-065-objects{position:absolute;inset:0;display:grid;grid-template-columns:repeat(3,1fr);place-items:center;pointer-events:none;perspective:500px}.d-backlog-065-objects i{width:22px;height:22px;border:1px solid #2e2e34;border-radius:8px;background:#161619;opacity:.72;will-change:transform,opacity;animation:d-backlog-065-float calc(2.7s + var(--i)*.13s) ease-in-out infinite alternate}.d-backlog-065-action{position:absolute;z-index:6;left:20px;bottom:18px;border:1px solid #2e2e34;border-radius:999px;background:#101012;color:#9b9ba3;padding:8px 12px;font:10px \"JetBrains Mono\",monospace;cursor:pointer;transition:color .2s,border-color .2s,transform .2s}.d-backlog-065-action:hover,.d-backlog-065-action:focus-visible{color:#c8ff2e;border-color:#c8ff2e;transform:translateY(-2px)}.d-backlog-065.d-backlog-065-active .d-backlog-065-objects i{background:#c8ff2e;border-color:#c8ff2e;opacity:.9}.d-backlog-065.d-backlog-065-active .d-backlog-065-action{color:#0a0a0b;background:#c8ff2e}@keyframes d-backlog-065-float{to{transform:translateY(-12px) rotate(9deg);opacity:.35}}@media(prefers-reduced-motion:reduce){.d-backlog-065-objects i{animation:none!important}.d-backlog-065-action{transition:none}}.d-backlog-065-scroller{position:absolute;inset:0;z-index:3;height:320px;overflow-y:auto;scrollbar-width:thin;scrollbar-color:#c8ff2e transparent}.d-backlog-065-spacer{height:1050px;display:flex;flex-direction:column;justify-content:space-around;padding:70px 30px 70px 78%;color:#ececef}.d-backlog-065-spacer strong{font:700 32px \"JetBrains Mono\",monospace}",
