    "js": "const canvas=root.querySelector('.d-backlog-092-canvas');\nconst ctx=canvas.getContext('2d');\nconst nodes=[].slice.call(root.querySelectorAll('.d-backlog-092-objects i'));\nconst hud=root.querySelector('.d-backlog-092-hud em');\nconst action=root.querySelector('.d-backlog-092-action');\nconst reduced=matchMedia('(prefers-reduced-motion: reduce)').matches;\nlet w=1,h=1,dpr=1,px=.5,py=.5,tx=.5,ty=.5,trail=[],active=false,drag=false,progress=0,last=performance.now();\nfunction resize(){const b=root.getBoundingClientRect();w=Math.max(1,b.width);h=Math.max(1,b.height);dpr=Math.min(devicePixelRatio||1,2);canvas.width=Math.round(w*dpr);canvas.height=Math.round(h*dpr);ctx.setTransform(dpr,0,0,dpr,0,0);}\nresize();window.addEventListener('resize',resize,{passive:true});\nfunction point(e){const b=root.getBoundingClientRect();tx=Math.max(0,Math.min(1,(e.clientX-b.left)/b.width));ty=Math.max(0,Math.min(1,(e.clientY-b.top)/b.height));trail.push([tx*w,ty*h,1]);if(trail.length>28)trail.shift();}\nroot.addEventListener('pointermove',point,{passive:true});root.addEventListener('pointerdown',function(e){drag=true;active=true;root.classList.add('d-backlog-092-active');point(e);},{passive:true});window.addEventListener('pointerup',function(){drag=false;},{passive:true});\naction.addEventListener('click',function(){active=!active;root.classList.toggle('d-backlog-092-active',active);action.textContent=active?'Reset':'Activate';progress=active?1:0;});\nfunction draw(now){const dt=Math.min(32,now-last)/16.667;last=now;px+=(tx-px)*(reduced?1:.075*dt);py+=(ty-py)*(reduced?1:.075*dt);if(!reduced)progress=(progress+.0015*dt)%1;ctx.fillStyle='#0a0a0b';ctx.fillRect(0,0,w,h);const id='image-infinite-zoom',cat='Image & WebGL';const time=reduced?0:now*.001;ctx.lineWidth=1;\nif(cat==='Raster & Glitch'){for(let y=0;y<h;y+=8){for(let x=0;x<w;x+=8){const wave=(Math.sin(x*.035+time)+Math.cos(y*.04-time)+2)/4;const near=Math.max(0,1-Math.hypot(x-px*w,y-py*h)/130);const on=wave+near*.55>((x/8+y/8)%4)/4;ctx.fillStyle=on?'#c8ff2e':'#161619';ctx.globalAlpha=.2+near*.8;ctx.fillRect(x+(id.indexOf('glitch')>=0&&active?Math.sin(y)*9:0),y,6,6);}}ctx.globalAlpha=1;}\nelse if(cat==='Cursor'){for(let i=0;i<18;i++){const a=i/18*Math.PI*2+time*.25,r=42+i*3+Math.sin(time*2+i)*9,x=px*w+Math.cos(a)*r,y=py*h+Math.sin(a)*r*.55;ctx.beginPath();ctx.arc(x,y,3+(i%4),0,Math.PI*2);ctx.fillStyle=i%3?'#2e2e34':'#c8ff2e';ctx.fill();}trail.forEach(function(p,i){p[2]*=.955;ctx.globalAlpha=p[2]*(i/trail.length);ctx.beginPath();ctx.arc(p[0],p[1],2+i*.22,0,Math.PI*2);ctx.fillStyle='#c8ff2e';ctx.fill();});ctx.globalAlpha=1;}\nelse if(cat==='Physics'){let x=px*w,y=py*h;ctx.strokeStyle='#5c5c66';ctx.beginPath();ctx.moveTo(x,y);for(let i=1;i<18;i++){x+=(w*.5-x)*.12;y+=(h*.72-y)*.1+Math.sin(time*2+i)*2;ctx.lineTo(x,y);}ctx.stroke();for(let i=0;i<12;i++){const q=i/11,xx=px*w+(w*.5-px*w)*q,yy=py*h+(h*.72-py*h)*q+Math.sin(q*Math.PI)*55;ctx.beginPath();ctx.arc(xx,yy,5,0,Math.PI*2);ctx.fillStyle=i===0?'#c8ff2e':'#2e2e34';ctx.fill();}}\nelse if(cat==='Liquid & Organic'){ctx.globalCompositeOperation='lighter';for(let i=0;i<11;i++){const a=i/11*Math.PI*2+time*.2,r=35+i*5,x=px*w+Math.cos(a)*r,y=py*h+Math.sin(a*1.3)*r*.55;const g=ctx.createRadialGradient(x,y,0,x,y,25);g.addColorStop(0,'#c8ff2e88');g.addColorStop(1,'#c8ff2e00');ctx.fillStyle=g;ctx.beginPath();ctx.arc(x,y,25,0,Math.PI*2);ctx.fill();}ctx.globalCompositeOperation='source-over';}\nelse if(cat==='Ambient'||cat==='Sound & Haptics'||cat==='Data & Numbers'){for(let i=0;i<44;i++){const x=(i*83+time*18*(i%3+1))%w,y=h*.5+Math.sin(i*1.7+time*(1+i%4)*.7)*h*.31;const near=Math.max(0,1-Math.hypot(x-px*w,y-py*h)/100);ctx.fillStyle=near?'#c8ff2e':'#5c5c66';ctx.fillRect(x,y,2+near*4,2+near*4);}}\nelse if(cat==='Text & Type'){const word=id.split('-').slice(1).join(' ').toUpperCase();ctx.font='700 '+Math.max(18,Math.min(42,w/(word.length*.65)))+'px JetBrains Mono';ctx.textAlign='center';for(let i=0;i<word.length;i++){const x=w/2+(i-(word.length-1)/2)*Math.min(34,w/(word.length+2)),y=h*.56+Math.sin(time*3+i*.7+(px-.5)*5)*18;ctx.fillStyle=i===Math.round(px*(word.length-1))?'#c8ff2e':'#ececef';ctx.fillText(word[i],x,y);}}\nelse if(cat==='SVG & Line'){ctx.strokeStyle='#c8ff2e';ctx.beginPath();for(let x=0;x<w;x+=3){const y=h*.55+Math.sin(x*.028+time*1.7)*42+Math.sin(x*.061-time)*18+(py-.5)*35;if(x)ctx.lineTo(x,y);else ctx.moveTo(x,y);}ctx.stroke();}\nelse if(cat==='Skeuomorph'){const a=-2.3+progress*4.6,cx=w*.5,cy=h*.55;ctx.fillStyle='#161619';ctx.strokeStyle='#2e2e34';ctx.lineWidth=8;ctx.beginPath();ctx.arc(cx,cy,62,0,Math.PI*2);ctx.fill();ctx.stroke();ctx.strokeStyle='#c8ff2e';ctx.lineWidth=3;ctx.beginPath();ctx.moveTo(cx,cy);ctx.lineTo(cx+Math.cos(a)*48,cy+Math.sin(a)*48);ctx.stroke();}\nelse if(cat==='Loaders & Progress'){ctx.strokeStyle='#232327';ctx.lineWidth=10;ctx.beginPath();ctx.arc(w/2,h*.55,58,0,Math.PI*2);ctx.stroke();ctx.strokeStyle='#c8ff2e';ctx.beginPath();ctx.arc(w/2,h*.55,58,-Math.PI/2,-Math.PI/2+progress*Math.PI*2);ctx.stroke();}\nelse if(cat==='Image & WebGL'||cat==='Galleries & Sliders'||cat==='3D & Perspective'){for(let i=0;i<7;i++){const q=(i-3-progress)*.14,x=w/2+q*w,y=h*.55+Math.abs(q)*45,s=1-Math.min(.55,Math.abs(q));ctx.save();ctx.translate(x,y);ctx.transform(1,q*.22,-q*.15,1,0,0);ctx.fillStyle=i===3?'#c8ff2e':'#161619';ctx.strokeStyle='#2e2e34';ctx.fillRect(-65*s,-48*s,130*s,96*s);ctx.strokeRect(-65*s,-48*s,130*s,96*s);ctx.restore();}}\nelse if(cat==='Buttons & Micro'||cat==='Navigation & Menus'){for(let i=0;i<4;i++){const x=w*.22+i*w*.19,y=h*.56;ctx.fillStyle=i===Math.round(progress*3)?'#c8ff2e':'#161619';ctx.strokeStyle='#2e2e34';ctx.beginPath();ctx.roundRect(x-42,y-16,84,32,16);ctx.fill();ctx.stroke();}}\nelse if(cat==='Play & Easter Eggs'){const x=24+(time*74)%(w-48),y=h*.58+Math.sin(time*2.2)*70;ctx.fillStyle='#c8ff2e';ctx.fillRect(x-18,y-9,36,18);for(let i=0;i<20;i++){ctx.fillStyle=i%3?'#232327':'#5c5c66';ctx.fillRect((i*47)%w,h*.78-(i%4)*13,7,7);}}\nelse{for(let i=0;i<9;i++){const col=i%3,row=Math.floor(i/3),cx=w*(.27+col*.23),cy=h*(.34+row*.2),spin=time*(.3+i*.025)+progress*4;ctx.save();ctx.translate(cx+(px-.5)*(i-4)*4,cy+(py-.5)*(i-4)*3);ctx.rotate(spin);ctx.strokeStyle=i===Math.round(progress*8)?'#c8ff2e':'#2e2e34';ctx.strokeRect(-22,-15,44,30);ctx.restore();}}\nnodes.forEach(function(n,i){const dx=(px-.5)*(i%3-1)*22,dy=(py-.5)*(Math.floor(i/3)-1)*18;const spin=(active?1:0)*(i-4)*3;n.style.transform='translate('+dx+'px,'+dy+'px) rotate('+spin+'deg) scale('+(1+(i===Math.round(progress*8)?.45:0))+')';});if(cat!=='Forms & Inputs')hud.textContent=String(Math.round(progress*99)).padStart(2,'0');requestAnimationFrame(draw);}\nrequestAnimationFrame(draw);",
    "prompt": "Build “Image Infinite Zoom” as a self-contained interaction: seamless infinite zoom through nested procedural frames. Structure the DOM as one position-relative 320px root with an accessible label, one decorative canvas or prefixed visual layer, a compact status HUD, and a real button or input for the primary action. Normalize pointer coordinates to 0–1 from the root bounding box; ease rendered coordinates toward the target each animation frame with current += (target - current) * 0.075, cap devicePixelRatio at 2, and clamp frame delta to 32ms. Use a 130px radial falloff max(0, 1 - distance / 130) for proximity responses and decay trail alpha by 0.955 per frame. Toggle active state on click or drag; for scroll variants derive progress as scrollTop / (scrollHeight - clientHeight). Animate with transform and opacity wherever DOM is involved, keep a single requestAnimationFrame loop, mark pointer and scroll listeners passive, and avoid layout reads inside the loop. Use #0a0a0b, #161619, #2e2e34, #ececef, and #c8ff2e with JetBrains Mono. Transitions use cubic-bezier(0.22, 1, 0.36, 1) over 300–650ms; stagger repeated parts by 35ms. Keep keyboard focus visible, expose pressed or muted state with aria-pressed, make canvas decorative, gate audio behind a gesture, and under prefers-reduced-motion render a representative static state with zero interpolation and no automatic cycling."
