    "seen": "Seen on: Stripe Checkout, Typeform, and Linear",
    "hint": "type, focus, and submit",
    "html": "<div class=\"d-backlog-177\" role=\"group\" aria-label=\"Input Shake Error interactive demonstration\" tabindex=\"0\"><canvas class=\"d-backlog-177-canvas\" aria-hidden=\"true\"></canvas><div class=\"d-backlog-177-hud\"><span>FORMS & INPUTS</span><b>Input Shake Error</b><em>00</em></div><div class=\"d-backlog-177-objects\" aria-hidden=\"true\"><i style=\"--i:0\"></i><i style=\"--i:1\"></i><i style=\"--i:2\"></i><i style=\"--i:3\"></i><i style=\"--i:4\"></i><i style=\"--i:5\"></i><i style=\"--i:6\"></i><i style=\"--i:7\"></i><i style=\"--i:8\"></i></div><label class=\"d-backlog-177-field\"><span>Interaction input</span><input maxlength=\"32\" placeholder=\"Type something\"><i></i></label><button class=\"d-backlog-177-action\" type=\"button\">Activate</button></div>",
    "css": ".d-backlog-177{position:relative;width:100%;height:320px;overflow:hidden;isolation:isolate;background:#0a0a0b;color:#ececef;touch-action:none;font-family:\"JetBrains Mono\",monospace}.d-backlog-177-canvas{position:absolute;inset:0;width:100%;height:100%}.d-backlog-177-hud{position:absolute;z-index:4;inset:18px 20px auto;display:grid;grid-template-columns:1fr auto;gap:5px;pointer-events:none}.d-backlog-177-hud span{color:#5c5c66;font-size:9px;letter-spacing:.14em}.d-backlog-177-hud b{grid-column:1;color:#ececef;font-size:13px;font-weight:500}.d-backlog-177-hud em{grid-row:1/3;grid-column:2;color:#c8ff2e;font-size:22px;font-style:normal}.d-backlog-177-objects{position:absolute;inset:0;display:grid;grid-template-columns:repeat(3,1fr);place-items:center;pointer-events:none;perspective:500px}.d-backlog-177-objects i{width:22px;height:22px;border:1px solid #2e2e34;border-radius:8px;background:#161619;opacity:.72;will-change:transform,opacity;animation:d-backlog-177-float calc(2.7s + var(--i)*.13s) ease-in-out infinite alternate}.d-backlog-177-action{position:absolute;z-index:6;left:20px;bottom:18px;border:1px solid #2e2e34;border-radius:999px;background:#101012;color:#9b9ba3;padding:8px 12px;font:10px \"JetBrains Mono\",monospace;cursor:pointer;transition:color .2s,border-color .2s,transform .2s}.d-backlog-177-action:hover,.d-backlog-177-action:focus-visible{color:#c8ff2e;border-color:#c8ff2e;transform:translateY(-2px)}.d-backlog-177.d-backlog-177-active .d-backlog-177-objects i{background:#c8ff2e;border-color:#c8ff2e;opacity:.9}.d-backlog-177.d-backlog-177-active .d-backlog-177-action{color:#0a0a0b;background:#c8ff2e}@keyframes d-backlog-177-float{to{transform:translateY(-12px) rotate(9deg);opacity:.35}}@media(prefers-reduced-motion:reduce){.d-backlog-177-objects i{animation:none!important}.d-backlog-177-action{transition:none}}.d-backlog-177-field{position:absolute;z-index:5;left:50%;top:51%;width:min(260px,70%);transform:translate(-50%,-50%);color:#9b9ba3;font:11px \"JetBrains Mono\",monospace}.d-backlog-177-field span{display:block;margin-bottom:8px}.d-backlog-177-field input{box-sizing:border-box;width:100%;border:1px solid #2e2e34;border-radius:8px;background:#101012;color:#ececef;padding:13px;outline:none}.d-backlog-177-field input:focus{border-color:#c8ff2e;box-shadow:0 0 0 3px #c8ff2e22}.d-backlog-177-field i{display:block;height:2px;background:#c8ff2e;transform:scaleX(0);transition:transform .3s}.d-backlog-177-field:focus-within i{transform:scaleX(1)}",
